# Create a Multi-AZ Auto Scaling group
aws autoscaling create-auto-scaling-group \n  --auto-scaling-group-name my-app-asg \n  --launch-template LaunchTemplateId=lt-0abc123,Version='' \n  --min-size 2 \n  --max-size 6 \n  --desired-capacity 2 \n  --availability-zones us-east-1a us-east-1b us-east-1c \n  --target-group-arns arn:aws:elasticloadbalancing:us-east-1:123456789012:targetgroup/my-tg/abc123

# Ensure min 1 instance per AZ using instance distribution
aws autoscaling update-auto-scaling-group \n  --auto-scaling-group-name my-app-asg \n  --mixed-instances-policy '{
    "InstancesDistribution": {
      "OnDemandBaseCapacity": 2,
      "OnDemandPercentageAboveBaseCapacity": 50,
      "SpotAllocationStrategy": "capacity-optimized"
    }
  }'

# Enable S3 Cross-Region Replication for geographic redundancy
aws s3api put-bucket-replication \n  --bucket my-primary-bucket \n  --replication-configuration '{
    "Role": "arn:aws:iam::123456789012:role/s3-replication-role",
    "Rules": [{
      "Status": "Enabled",
      "Prefix": "",
      "Destination": {
        "Bucket": "arn:aws:s3:::my-dr-bucket-eu-west-1",
        "StorageClass": "STANDARD_IA"
      }
    }]
  }'

# Enable versioning (required for replication)
aws s3api put-bucket-versioning \n  --bucket my-primary-bucket \n  --versioning-configuration Status=Enabled

# Create a FIS experiment to terminate EC2 instances in one AZ
aws fis create-experiment-template \n  --description 'Terminate 50% of instances in us-east-1a' \n  --actions '{
    "terminateInstances": {
      "actionId": "aws:ec2:terminate-instances",
      "parameters": { "durationSeconds": "60" },
      "targets": { "Instances": "half-in-az-a" }
    }
  }' \n  --targets '{
    "half-in-az-a": {
      "resourceType": "aws:ec2:instance",
      "resourceTags": { "Environment": "staging" },
      "filters": [{ "path": "Placement.AvailabilityZone", "values": ["us-east-1a"] }],
      "selectionMode": "PERCENT(50)"
    }
  }' \n  --stop-conditions '[{"source": "aws:cloudwatch:alarm", "value": "arn:aws:cloudwatch:us-east-1:123:alarm:error-rate-high"}]' \n  --role-arn arn:aws:iam::123456789012:role/fis-execution-role

import boto3, time, random
from botocore.config import Config

# AWS SDK retry config: exponential backoff with jitter, up to 5 retries
client = boto3.client(
    'dynamodb',
    config=Config(
        retries={
            'max_attempts': 5,
            'mode': 'adaptive'   # adaptive mode adds client-side rate limiting
        },
        read_timeout=3,          # seconds
        connect_timeout=2
    )
)

# Manual exponential backoff for custom logic
def call_with_backoff(fn, max_retries=4):
    for attempt in range(max_retries):
        try:
            return fn()
        except Exception as e:
            if attempt == max_retries - 1:
                raise
            wait = (2 ** attempt) + random.uniform(0, 1)   # jitter
            time.sleep(wait)

# Configure a DLQ for an async Lambda function
aws lambda put-function-event-invoke-config \
  --function-name order-processor \
  --maximum-retry-attempts 2 \
  --destination-config '{
    "OnFailure": {
      "Destination": "arn:aws:sqs:us-east-1:123456789012:order-dlq"
    }
  }'

# Check the DLQ message count for monitoring
aws sqs get-queue-attributes \
  --queue-url https://sqs.us-east-1.amazonaws.com/123456789012/order-dlq \
  --attribute-names ApproximateNumberOfMessages
